llm_response.terraform_block:
data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

resource "aws_cloudwatch_log_group" "eks_production_cluster_logs" {
  name              = "/aws/eks/production-cluster"
  retention_in_days = 7

  tags = {
    FinOpsAction   = "S3_ARCHIVAL"
    FinOpsReviewed = "true"
    Name           = "eks-production-cluster-logs"
    Environment    = "production"
  }
}

resource "aws_s3_bucket" "eks_production_cluster_logs_archive" {
  bucket = "eks-production-cluster-logs-archive-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
  acl    = "private"

  tags = {
    FinOpsAction   = "S3_ARCHIVAL"
    FinOpsReviewed = "true"
    Name           = "eks-production-cluster-logs-archive"
    Environment    = "production"
  }
}

resource "aws_s3_bucket_versioning" "eks_production_cluster_logs_archive_versioning" {
  bucket = aws_s3_bucket.eks_production_cluster_logs_archive.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "eks_production_cluster_logs_archive_sse" {
  bucket = aws_s3_bucket.eks_production_cluster_logs_archive.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "eks_production_cluster_logs_archive_public_access_block" {
  bucket = aws_s3_bucket.eks_production_cluster_logs_archive.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_iam_role" "firehose_to_s3_role" {
  name = "firehose-to-s3-eks-production-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    FinOpsAction   = "S3_ARCHIVAL"
    FinOpsReviewed = "true"
    Name           = "firehose-to-s3-eks-production-cluster-role"
    Environment    = "production"
  }
}

resource "aws_iam_role_policy" "firehose_to_s3_policy" {
  name = "firehose-to-s3-eks-production-cluster-policy"
  role = aws_iam_role.firehose_to_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.eks_production_cluster_logs_archive.arn,
          "${aws_s3_bucket.eks_production_cluster_logs_archive.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesisfirehose/*:stream/*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "eks_production_cluster_firehose" {
  name        = "eks-production-cluster-logs-firehose"
  destination = "s3"

  s3_configuration {
    role_arn            = aws_iam_role.firehose_to_s3_role.arn
    bucket_arn          = aws_s3_bucket.eks_production_cluster_logs_archive.arn
    prefix              = "logs/eks-production-cluster/"
    error_output_prefix = "errors/eks-production-cluster/"

    buffering_interval = 300
    buffering_size     = 5

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/eks-production-cluster-logs-firehose"
      log_stream_name = "DestinationDelivery"
    }
  }

  tags = {
    FinOpsAction   = "S3_ARCHIVAL"
    FinOpsReviewed = "true"
    Name           = "eks-production-cluster-logs-firehose"
    Environment    = "production"
  }
}

resource "aws_cloudwatch_log_group" "firehose_error_logs" {
  name              = "/aws/kinesisfirehose/eks-production-cluster-logs-firehose"
  retention_in_days = 30

  tags = {
    FinOpsAction   = "S3_ARCHIVAL"
    FinOpsReviewed = "true"
    Name           = "eks-production-cluster-firehose-error-logs"
    Environment    = "production"
  }
}

resource "aws_cloudwatch_log_subscription_filter" "eks_production_cluster_s3_archival" {
  name            = "eks-production-cluster-s3-archival-filter"
  log_group_name  = aws_cloudwatch_log_group.eks_production_cluster_logs.name
  destination_arn = aws_kinesis_firehose_delivery_stream.eks_production_cluster_firehose.arn
  filter_pattern  = ""
}

